+        // First chunks are full size
+        assert_eq!(manifest.chunk_size_at(0).unwrap(), 64 * 1024);
+        assert_eq!(manifest.chunk_size_at(1).unwrap(), 64 * 1024);
+        assert_eq!(manifest.chunk_size_at(2).unwrap(), 64 * 1024);
+        // Last chunk is remainder
