+        assert_eq!(config.symbol_size, 1024);
+        assert_eq!(config.repair_ratio_bps, 500);
+        assert_eq!(config.max_object_size, 64 * 1024 * 1024);
+        assert_eq!(config.decode_timeout, Duration::from_secs(30));
